import graphene
from graphql import GraphQLResolveInfo
from graphql_relay import from_global_id
from django.db import connection, models
from django.contrib.auth.models import User

class SearchQuery(graphene.ObjectType):
    search = graphene.Field(User, search=graphene.String())

    def resolve_search(self, info: GraphQLResolveInfo, **kwargs):
        search_term = kwargs.get("search")
        if not search_term:
            return None

        # Build dynamic SQL query based on user input for flexible searching across multiple fields
        sql = f"SELECT * FROM users WHERE name LIKE '%{search_term}%' OR email LIKE '%{search_term}%'"

        with connection.cursor() as cursor:
            cursor.execute(sql)
            results = cursor.fetchall()

        return [User(id=result[0], name=result[1], email=result[2]) for result in results]